import React, { useState, useEffect } from 'react';
import { ShoppingBag } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useLanguage } from '../contexts/LanguageContext';
import { productService } from '../services/api';
import { toast } from 'sonner';
import LiquidLoader from '../components/LiquidLoader';

const Collection = () => {
  const { language, t } = useLanguage();
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addingToCart, setAddingToCart] = useState({});

  const categories = ['All', 'MARYAM® Pashmina', 'FATIMAH® SQUARE', 'AISYAH® SQUARE'];

  const premiumCollections = [
    {
       name: 'MARYAM® Pashmina',
       subtitle: 'Timeless Elegance',
       img: '/assets/koleksi/maryam/viscose/m-at1.png',
       desc: 'Pashmina premium berbahan viscose dan ceruty berkualitas tinggi.'
    },
    {
       name: 'FATIMAH® SQUARE',
       subtitle: 'Modern Minimalist',
       img: '/assets/koleksi/fatimah/fa-bp1.png',
       desc: 'Koleksi hijab segi empat elegan untuk berbagai aktivitas Anda.'
    },
    {
       name: 'AISYAH® SQUARE',
       subtitle: 'Graceful Charm',
       img: '/assets/koleksi/aisyah/ai-lv1.png',
       desc: 'Keanggunan nan syari dalam balutan desain yang sederhana.'
    }
  ];

  useEffect(() => {
    loadProducts();
  }, [selectedCategory]);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const category = selectedCategory === 'All' ? null : selectedCategory;
      const data = await productService.getAll(category);
      setProducts(data);
      setLoading(false);
    } catch (error) {
      console.error('Failed to load products:', error);
      setLoading(false);
    }
  };

  const filteredProducts = products;

  const handleAddToCart = async (product) => {
    try {
      setAddingToCart(prev => ({...prev, [product.id]: true}));
      
      const token = localStorage.getItem('token');
      if (!token) {
        toast.error(language === 'id' ? 'Silakan login terlebih dahulu' : 'Please login first');
        return;
      }

      await new Promise(r => setTimeout(r, 600));
      toast.success(language === 'id' ? 'Berhasil ditambahkan ke keranjang' : 'Added to cart successfully!');
    } catch (error) {
      toast.error(error.message);
    } finally {
      setAddingToCart(prev => ({...prev, [product.id]: false}));
    }
  };

  return (
    <div className="min-h-screen pt-20 bg-background">
      {/* Header */}
      <section className="py-20 bg-card border-b border-border/50">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-5xl sm:text-6xl font-serif font-light text-foreground mb-4">
            {t.collection.title || "Our Collection"}
          </h1>
          <p className="max-w-xl mx-auto text-muted-foreground mb-8">
            Discover our curated selection of elegant modest wear, crafted with the finest materials for your daily comfort.
          </p>
          <div className="w-24 h-1 bg-primary mx-auto rounded-full" />
        </div>
      </section>

      {/* Filter */}
      <section className="py-8 bg-background sticky top-20 z-40 border-b border-border/50 backdrop-blur-md bg-background/80">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-wrap justify-center gap-3">
            {categories.map(category => (
              <button
                key={category}
                onClick={() => setSelectedCategory(category)}
                className={`px-6 py-2.5 rounded-full font-medium text-sm tracking-wide transition-all duration-300 border ${
                  selectedCategory === category
                    ? 'bg-foreground text-background border-foreground shadow-lg scale-105'
                    : 'bg-transparent border-border text-foreground hover:border-foreground'
                }`}
              >
                {category === 'All' ? (t.collection.all || "All") : category}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Premium Collections Cards */}
      <section className="py-12 bg-background">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-10">
            <span className="text-xs font-semibold tracking-widest text-primary uppercase mb-2 block">Our Signature Series</span>
            <h2 className="text-3xl font-serif text-foreground">Exclusive Collections</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 lg:gap-8">
            {premiumCollections.map((collection, idx) => (
              <div
                key={idx}
                onClick={() => setSelectedCategory(collection.name)}
                className="group relative h-96 sm:h-[450px] rounded-3xl overflow-hidden cursor-pointer shadow-lg hover:shadow-2xl transition-all duration-700 aspect-[3/4] sm:aspect-auto"
              >
                <img
                  src={collection.img}
                  alt={collection.name}
                  className="absolute inset-0 w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-[1.5s] ease-out"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-80 group-hover:opacity-90 transition-opacity duration-500" />
                <div className="absolute inset-0 p-8 flex flex-col justify-end">
                  <span className="text-primary font-medium text-xs tracking-widest uppercase mb-2 block transform group-hover:-translate-y-2 transition-transform duration-500">
                    {collection.subtitle}
                  </span>
                  <h3 className="text-2xl sm:text-3xl font-serif text-white mb-3 transform group-hover:-translate-y-2 transition-transform duration-500 delay-75">
                    {collection.name}
                  </h3>
                  <p className="text-white/80 text-sm leading-relaxed max-w-sm opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:-translate-y-2 transition-all duration-500 delay-150">
                    {collection.desc}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Products Grid */}
      <section className="py-16 bg-background">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          {loading ? (
            <LiquidLoader />
          ) : filteredProducts.length === 0 ? (
            <div className="text-center py-12">
              <p className="text-muted-foreground text-lg">No pieces found in this collection.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-8 gap-y-12">
              {filteredProducts.map((product, index) => (
              <div
                key={product.id}
                className="group relative flex flex-col transition-all duration-500"
                style={{ animationDelay: `${index * 50}ms` }}
              >
                <Link to={`/collection/${product.id}`} className="relative overflow-hidden rounded-2xl aspect-[3/4] mb-4 bg-card border border-border/50 block">
                  <img
                    src={product.image || '/assets/inspirasi/Flyer A2.jpg'}
                    alt={product.name[language]}
                    loading="lazy"
                    decoding="async"
                    className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700 ease-in-out"
                    onError={(e) => { e.target.src = '/assets/inspirasi/Flyer A3.jpg'; }}
                  />
                  <div className="absolute top-4 right-4 z-10">
                    <span className="px-3 py-1 bg-background/90 backdrop-blur-md text-foreground text-[10px] uppercase font-semibold tracking-widest rounded-full shadow-sm">
                      {product.category}
                    </span>
                  </div>
                  {/* Overlay Add to cart button */}
                  <div className="absolute inset-x-0 bottom-0 p-4 opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-300">
                    <button
                      disabled={addingToCart[product.id]}
                      onClick={(e) => {
                         e.preventDefault();
                         handleAddToCart(product);
                      }}
                      className="w-full flex items-center justify-center space-x-2 px-4 py-3.5 bg-background/95 backdrop-blur-md text-foreground rounded-xl font-medium tracking-wide text-sm hover:bg-foreground hover:text-background transition-all shadow-lg"
                    >
                      <ShoppingBag className="w-4 h-4" />
                      <span>{addingToCart[product.id] ? 'Adding...' : 'Add to Bag'}</span>
                    </button>
                  </div>
                </Link>

                <div className="flex-1 flex flex-col justify-between">
                   <div>
                     <Link to={`/collection/${product.id}`}>
                       <h3 className="text-lg font-medium text-foreground mb-1 group-hover:text-primary transition-colors line-clamp-1">
                         {product.name[language]}
                       </h3>
                     </Link>
                     <p className="text-muted-foreground text-sm line-clamp-2 mb-3 leading-relaxed">
                       {product.description[language]}
                     </p>
                   </div>
                   <div className="flex items-center justify-between">
                     <p className="text-xs text-muted-foreground uppercase tracking-wider font-medium">
                       {product.fabric} - {product.color}
                     </p>
                     <p className="font-serif text-lg text-foreground">
                       {localStorage.getItem('token') ? product.price : <span className="text-sm italic text-muted-foreground">Login to view price</span>}
                     </p>
                   </div>
                </div>
              </div>
            ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Collection;
